import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { Plus, ArrowUpCircle, X, DollarSign, Calendar, Landmark } from 'lucide-react';
import '../styles/Proventos.css';

const Proventos = () => {
  const [lista, setLista] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [form, setForm] = useState({ 
    descricao: '', 
    valor: '', 
    categoria: 'Salário', 
    data: new Date().toISOString().split('T')[0] 
  });

  useEffect(() => {
    buscarProventos();
  }, []);

  async function buscarProventos() {
    setLoading(true);
    const { data } = await supabase.from('proventos').select('*').order('data_recebimento', { ascending: false });
    setLista(data || []);
    setLoading(false);
  }

  async function handleSalvar(e) {
    e.preventDefault();
    const { data: { user } } = await supabase.auth.getUser();
    
    const { error } = await supabase.from('proventos').insert([{
      user_id: user.id,
      descricao: form.descricao,
      valor: parseFloat(form.valor),
      categoria: form.categoria,
      data_recebimento: form.data
    }]);

    if (!error) {
      setForm({ ...form, descricao: '', valor: '' });
      setShowModal(false);
      buscarProventos();
    }
  }

  const formatMoney = (v) => v.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });

  return (
    <div className="proventos-container fade-in">
      <header className="proventos-header">
        <div>
          <h2>Receitas e Proventos</h2>
          <p>Gerencie suas entradas financeiras</p>
        </div>
        <div className="header-total-box">
          <span className="label-total">Total Recebido</span>
          <span className="value-total">
            {formatMoney(lista.reduce((acc, cur) => acc + parseFloat(cur.valor), 0))}
          </span>
        </div>
      </header>

      <div className="proventos-card list-full-section">
        <h3>Histórico de Entradas</h3>
        <div className="scroll-list-large">
          {loading ? (
            <div className="loading-msg">Carregando proventos...</div>
          ) : lista.length > 0 ? (
            lista.map(item => (
              <div key={item.id} className="income-item-row">
                <div className="inc-icon"><Landmark size={20} /></div>
                <div className="income-info">
                  <span className="inc-desc">{item.descricao}</span>
                  <span className="inc-cat">{item.categoria} • {new Date(item.data_recebimento).toLocaleDateString()}</span>
                </div>
                <span className="inc-value">{formatMoney(item.valor)}</span>
              </div>
            ))
          ) : (
            <div className="empty-state">Nenhuma receita registrada.</div>
          )}
        </div>
      </div>

      {/* Botão Flutuante */}
      <button className="fab-button income" onClick={() => setShowModal(true)}>
        <Plus size={28} />
      </button>

      {/* Modal de Lançamento */}
      {showModal && (
        <div className="modal-overlay" onClick={() => setShowModal(false)}>
          <div className="modal-content side-modal fade-in" onClick={e => e.stopPropagation()}>
            <div className="modal-header-simple">
              <h3>Nova Receita</h3>
              <button className="close-btn" onClick={() => setShowModal(false)}><X size={20}/></button>
            </div>
            
            <form onSubmit={handleSalvar} className="modal-form">
              <div className="input-group">
                <label>Descrição</label>
                <input type="text" required value={form.descricao} onChange={e => setForm({...form, descricao: e.target.value})} placeholder="Ex: Salário" />
              </div>
              <div className="input-group">
                <label>Valor</label>
                <input type="number" step="0.01" required value={form.valor} onChange={e => setForm({...form, valor: e.target.value})} placeholder="0,00" />
              </div>
              <div className="input-group">
                <label>Categoria</label>
                <select value={form.categoria} onChange={e => setForm({...form, categoria: e.target.value})}>
                  <option value="Salário">Salário</option>
                  <option value="Extra">Renda Extra</option>
                  <option value="Investimento">Investimento</option>
                  <option value="Outros">Outros</option>
                </select>
              </div>
              <div className="input-group">
                <label>Data</label>
                <input type="date" required value={form.data} onChange={e => setForm({...form, data: e.target.value})} />
              </div>
              <button type="submit" className="btn-confirm-income">Salvar Receita</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Proventos;
